type WebhookEndpointUpdate struct {
	Enabled *bool               `json:"enabled,omitempty"`
	Events  *[]WebhookEventType `json:"events,omitempty"`

	// Format Payload serialization format.
	//   - json (default): rosshield raw JSON envelope.
	//   - cef: ArcSight Common Event Format (Splunk OOTB).
	//   - ecs: Elastic Common Schema.
	Format *WebhookFormat `json:"format,omitempty"`
	Secret string         `json:"secret"`
	Url    string         `json:"url"`
}

// WebhookEventType Domain event type subscribed by the webhook. Empty `events` means all known
// events. Add new types only after operator agreement (signed pack).
type WebhookEventType string

// WebhookFormat Payload serialization format.
//   - json (default): rosshield raw JSON envelope.
//   - cef: ArcSight Common Event Format (Splunk OOTB).
//   - ecs: Elastic Common Schema.
type WebhookFormat string

// WebhookTestResponse Result of a one-off ping. `success=true` iff the upstream returned a 2xx
// status. Transport-level failures (DNS, TLS, timeout) populate `error` with
// a human-readable message and leave `status=0`.
type WebhookTestResponse struct {
	// Error Transport or upstream error message
	Error *string `json:"error,omitempty"`

	// LatencyMs Round-trip time in milliseconds
	LatencyMs int64 `json:"latencyMs"`

	// Status HTTP status (0 if transport error)
	Status  int  `json:"status"`
	Success bool `json:"success"`
}

